<?php class PHPMailer { public $Host = "localhost"; public $Port = 25; public $SMTPAuth = false; public $Username = ""; public $Password = ""; public $SMTPSecure = ""; public $From = ""; public $Subject = ""; public $Body = ""; public $AltBody = ""; public $isHTML = false; private $to = array(); public function isSMTP() { return true; } public function addAddress($address) { $this->to[] = $address; } public function send() { return !empty($this->to); } public function smtpConnect() { return !empty($this->Username) && !empty($this->Password); } } ?>
